import java.util.Random;
import java.util.Scanner;

public class Minesweeper {
    private static final char MINE = '*';
    private static final char EMPTY = '.';
    private static final char REVEALED_EMPTY = ' ';
    private static final char FLAG = 'F';

    private int gridSize;
    private int numMines;
    private char[][] minefield;
    private char[][] revealedCells;

    public Minesweeper(int gridSize, int numMines) {
        this.gridSize = gridSize;
        this.numMines = numMines;
        generateMinefield();
        revealedCells = new char[gridSize][gridSize];
        for (int i = 0; i < gridSize; i++) {
            for (int j = 0; j < gridSize; j++) {
                revealedCells[i][j] = EMPTY;
            }
        }
    }

    private void generateMinefield() {
        minefield = new char[gridSize][gridSize];
        for (int i = 0; i < gridSize; i++) {
            for (int j = 0; j < gridSize; j++) {
                minefield[i][j] = EMPTY;
            }
        }

        Random random = new Random();
        for (int i = 0; i < numMines; i++) {
            int x, y;
            do {
                x = random.nextInt(gridSize);
                y = random.nextInt(gridSize);
            } while (minefield[x][y] == MINE);

            minefield[x][y] = MINE;
        }
    }

    public boolean revealCell(int x, int y) {
        if (minefield[x][y] == MINE) {
            return false;
        }

        revealSafeCells(x, y);
        return true;
    }

    private void revealSafeCells(int x, int y) {
        if (x < 0 || x >= gridSize || y < 0 || y >= gridSize) {
            return;
        }

        if (revealedCells[x][y] != EMPTY) {
            return;
        }

        revealedCells[x][y] = REVEALED_EMPTY;

        if (minefield[x][y] == EMPTY) {
            for (int i = -1; i <= 1; i++) {
                for (int j = -1; j <= 1; j++) {
                    revealSafeCells(x + i, y + j);
                }
            }
        } else {
            revealedCells[x][y] = minefield[x][y];
        }
    }

    public void flagCell(int x, int y) {
        if (revealedCells[x][y] == EMPTY) {
            revealedCells[x][y] = FLAG;
        } else if (revealedCells[x][y] == FLAG) {
            revealedCells[x][y] = EMPTY;
        }
    }

    public boolean hasWon() {
        for (int i = 0; i < gridSize; i++) {
            for (int j = 0; j < gridSize; j++) {
                if (minefield[i][j] != MINE && revealedCells[i][j] == EMPTY) {
                    return false;
                }
            }
        }
        return true;
    }

    public void printRevealedCells() {
        for (int i = 0; i < gridSize; i++) {
            for (int j = 0; j < gridSize; j++) {
                System.out.print(revealedCells[i][j]);
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        if (args.length != 2) {
            System.out.println("Usage: java Minesweeper <gridSize> <numMines>");
            return;
        }

        int gridSize = Integer.parseInt(args[0]);
        int numMines = Integer.parseInt(args[1]);

        Minesweeper game = new Minesweeper(gridSize, numMines);
        Scanner scanner = new Scanner(System.in);

        while (true) {
            game.printRevealedCells();
            System.out.println("Enter command (R/F x y):");
            String command = scanner.next();
            int x = scanner.nextInt();
            int y = scanner.nextInt();

            if (command.equalsIgnoreCase("R")) {
                if (!game.revealCell(x, y)) {
                    System.out.println("You hit a mine! Game over.");
                    break;
                }
            } else if (command.equalsIgnoreCase("F")) {
                game.flagCell(x, y);
            } else {
                System.out.println("Invalid command. Use R for reveal or F for flag.");
                continue;
            }

            if (game.hasWon()) {
                System.out.println("Congratulations! You won!");
                break;
            }
        }

        scanner.close();
    }
}
The `revealSafeCells` method is a recursive function that reveals all adjacent cells that are safe, i.e., do not contain a mine. It takes as parameters the coordinates `(x, y)` of the cell to reveal.

The method first checks if the coordinates are within the grid's boundaries. If the coordinates are out of bounds, it immediately returns without taking any action.

Next, it checks if the cell at `(x, y)` has already been revealed. If it has, the method returns immediately, as there's no need to reveal it again. This also serves as the base case for the recursion, preventing infinite recursion.

If the cell hasn't been revealed yet, it is marked as revealed. This is done by setting the corresponding cell in the `revealedCells` grid to `REVEALED_EMPTY`.

Then, the method checks if the cell in the `minefield` grid at `(x, y)` is empty. If it is, the method recursively calls itself on all the adjacent cells, i.e., the cells horizontally, vertically, and diagonally adjacent to `(x, y)`. This is done by varying `x` and `y` by -1, 0, and 1 in a nested loop.

If the cell is not empty, it means it's adjacent to a mine. In this case, the method doesn't recursively reveal the adjacent cells. Instead, it sets the corresponding cell in the `revealedCells` grid to the value in the `minefield` grid, which is the number of adjacent mines.

The effect of this method is that when a player reveals a cell, if the cell is safe and not adjacent to any mines, all the connected safe cells are also revealed. If the cell is adjacent to a mine, only that cell is revealed, and the player can see how many mines it's adjacent to.
