Here's a Golang program that accepts two command-line arguments: a string pattern and a directory path. The program searches for files within the specified directory (recursively) that match the given pattern and prints their absolute paths.

```go
package main

import (
	"fmt"
	"os"
	"path/filepath"
	"regexp"
)

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run main.go <pattern> <directory>")
		os.Exit(1)
	}

	pattern := os.Args[1]
	dirPath := os.Args[2]

	err := filepath.Walk(dirPath, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if !info.IsDir() {
			matched, err := regexp.MatchString(pattern, filepath.Base(path))
			if err != nil {
				return err
			}
			if matched {
				absPath, _ := filepath.Abs(path)
				fmt.Println(absPath)
			}
		}
		return nil
	})

	if err != nil {
		fmt.Printf("Error walking the path %q: %v\n", dirPath, err)
	}
}
```

